import{_ as d,o as e,c as o,a2 as c}from"./chunks/framework.BFVZdVmd.js";const u=JSON.parse('{"title":"学习路线与重点记忆","description":"","frontmatter":{},"headers":[],"relativePath":"overview/roadmap.md","filePath":"overview/roadmap.md","lastUpdated":null}'),r={name:"overview/roadmap.md"};function a(i,t,l,n,s,p){return e(),o("div",null,[...t[0]||(t[0]=[c('<h1 id="学习路线与重点记忆" tabindex="-1">学习路线与重点记忆 <a class="header-anchor" href="#学习路线与重点记忆" aria-label="Permalink to &quot;学习路线与重点记忆&quot;">​</a></h1><h2 id="最小学习路线" tabindex="-1">最小学习路线 <a class="header-anchor" href="#最小学习路线" aria-label="Permalink to &quot;最小学习路线&quot;">​</a></h2><p>学习企业 Java Spring Cloud，不建议一开始学全部。推荐顺序：</p><ol><li><code>Java 基础</code></li><li><code>Spring Boot</code></li><li><code>MyBatis-Plus + MySQL</code></li><li><code>Redis</code></li><li><code>Spring Security / JWT</code></li><li><code>Spring Cloud 基础</code></li><li><code>Nacos 注册中心和配置中心</code></li><li><code>OpenFeign 服务调用</code></li><li><code>Spring Cloud Gateway</code></li><li><code>Sentinel 熔断限流</code></li><li><code>Elasticsearch</code></li><li><code>RocketMQ / Kafka</code></li><li><code>XXL-Job</code></li><li><code>MinIO / OSS</code></li><li><code>Actuator + Prometheus + Grafana</code></li><li><code>SkyWalking / OpenTelemetry</code></li><li><code>Docker</code></li><li><code>Kubernetes</code></li><li><code>CI/CD</code></li><li><code>Seata / ShardingSphere / Canal</code></li></ol><h2 id="重点记忆版" tabindex="-1">重点记忆版 <a class="header-anchor" href="#重点记忆版" aria-label="Permalink to &quot;重点记忆版&quot;">​</a></h2><p>企业 Spring Cloud 项目可以按这些问题来记：</p><table tabindex="0"><thead><tr><th>问题</th><th>技术选型</th></tr></thead><tbody><tr><td>服务怎么启动</td><td><code>Spring Boot</code></td></tr><tr><td>服务怎么治理</td><td><code>Spring Cloud</code></td></tr><tr><td>服务怎么注册发现</td><td><code>Nacos / Eureka / Consul</code></td></tr><tr><td>配置怎么统一管理</td><td><code>Nacos Config / Spring Cloud Config</code></td></tr><tr><td>请求从哪里进来</td><td><code>Gateway / Nginx / APISIX</code></td></tr><tr><td>服务之间怎么调用</td><td><code>OpenFeign / Dubbo</code></td></tr><tr><td>服务挂了怎么办</td><td><code>Sentinel / Resilience4j</code></td></tr><tr><td>数据存哪里</td><td><code>MySQL / PostgreSQL</code></td></tr><tr><td>数据怎么访问</td><td><code>MyBatis-Plus / JPA</code></td></tr><tr><td>热点数据怎么加速</td><td><code>Redis</code></td></tr><tr><td>分布式锁怎么做</td><td><code>Redisson</code></td></tr><tr><td>搜索怎么做</td><td><code>Elasticsearch</code></td></tr><tr><td>异步消息怎么做</td><td><code>RocketMQ / Kafka / RabbitMQ</code></td></tr><tr><td>分布式事务怎么做</td><td><code>Seata / 事务消息</code></td></tr><tr><td>文件放哪里</td><td><code>MinIO / OSS / S3</code></td></tr><tr><td>定时任务怎么做</td><td><code>XXL-Job / Quartz</code></td></tr><tr><td>登录权限怎么做</td><td><code>Spring Security / OAuth2 / JWT / Sa-Token</code></td></tr><tr><td>接口文档怎么做</td><td><code>Knife4j / Springdoc OpenAPI</code></td></tr><tr><td>日志怎么查</td><td><code>ELK / Loki</code></td></tr><tr><td>链路怎么追踪</td><td><code>SkyWalking / OpenTelemetry</code></td></tr><tr><td>指标怎么监控</td><td><code>Prometheus + Grafana</code></td></tr><tr><td>代码质量怎么管</td><td><code>SonarQube / JaCoCo / Checkstyle</code></td></tr><tr><td>怎么部署</td><td><code>Docker / Kubernetes / Helm</code></td></tr><tr><td>怎么自动发布</td><td><code>Jenkins / GitLab CI / Argo CD</code></td></tr></tbody></table>',7)])])}const h=d(r,[["render",a]]);export{u as __pageData,h as default};
